import xml.etree.ElementTree as ET

def validate_xml(xml_data):
    try:
        # Parse the XML data
        root = ET.fromstring(xml_data)
        
        # Perform basic validation (e.g., check for specific tags or attributes)
        if root.tag != 'Document':
            raise ValueError("Root element is not 'Document'")
        
        # Example: Check if a required attribute exists
        if 'version' not in root.attrib:
            raise ValueError("Missing 'version' attribute in the root element")
        
        print("XML is valid.")
        return True
    
    except ET.ParseError as e:
        print(f"Invalid XML: {e}")
        return False
    except ValueError as ve:
        print(ve)
        return False

